"use client"

import { useState } from "react"
import { useDataStore } from "@/store/data-store"
import { useAuthStore } from "@/store/auth-store"
import { PageHeader } from "@/components/shared/page-header"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  MoreHorizontal,
  Pencil,
  Trash2,
  Search,
  Users,
  Eye,
  Phone,
  Mail,
  GitBranch,
  UserCog,
} from "lucide-react"
import type { Engineer, EntityStatus } from "@/lib/types"
import { toast } from "sonner"

export default function EngineersPage() {
  const { currentUser } = useAuthStore()
  const {
    engineers,
    branches,
    teams,
    addEngineer,
    updateEngineer,
    deleteEngineer,
    getBranchesByDMA,
    getTeamsByDMA,
  } = useDataStore()
  const [search, setSearch] = useState("")
  const [statusFilter, setStatusFilter] = useState<string>("all")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [detailOpen, setDetailOpen] = useState(false)
  const [editingEngineer, setEditingEngineer] = useState<Engineer | null>(null)
  const [viewingEngineer, setViewingEngineer] = useState<Engineer | null>(null)
  const [deleteId, setDeleteId] = useState<string | null>(null)

  // Form state
  const [formName, setFormName] = useState("")
  const [formEmail, setFormEmail] = useState("")
  const [formPhone, setFormPhone] = useState("")
  const [formBranchId, setFormBranchId] = useState("")
  const [formTeamId, setFormTeamId] = useState("")
  const [formRole, setFormRole] = useState<"engineer" | "team_leader">(
    "engineer"
  )
  const [formStatus, setFormStatus] = useState<EntityStatus>("active")

  // Only DMA managers can access this page
  const isDMAManager = currentUser?.role === "dma_manager"
  if (!isDMAManager) {
    return (
      <div className="flex flex-col gap-6">
        <PageHeader
          title="Engineers Management"
          description="Only DMA Managers can manage engineers"
        />
        <Card>
          <CardContent className="py-12 text-center text-muted-foreground">
            You do not have permission to access this page. Only DMA Managers can manage engineers.
          </CardContent>
        </Card>
      </div>
    )
  }

  const dmaId = currentUser?.dmaId ?? ""
  const myBranches = getBranchesByDMA(dmaId)
  const myTeams = getTeamsByDMA(dmaId)

  // Filter engineers to this DMA
  const scopedEngineers = engineers.filter((e) => e.dmaId === dmaId)

  const filteredEngineers = scopedEngineers.filter((e) => {
    const matchSearch =
      e.name.toLowerCase().includes(search.toLowerCase()) ||
      e.email.toLowerCase().includes(search.toLowerCase()) ||
      e.branchName.toLowerCase().includes(search.toLowerCase())
    const matchStatus = statusFilter === "all" || e.status === statusFilter
    return matchSearch && matchStatus
  })

  function openCreateDialog() {
    setEditingEngineer(null)
    setFormName("")
    setFormEmail("")
    setFormPhone("")
    setFormBranchId("")
    setFormTeamId("")
    setFormRole("engineer")
    setFormStatus("active")
    setDialogOpen(true)
  }

  function openEditDialog(engineer: Engineer) {
    setEditingEngineer(engineer)
    setFormName(engineer.name)
    setFormEmail(engineer.email)
    setFormPhone(engineer.phone)
    setFormBranchId(engineer.branchId)
    setFormTeamId(engineer.teamId ?? "")
    setFormRole(engineer.role)
    setFormStatus(engineer.status)
    setDialogOpen(true)
  }

  function handleSubmit() {
    if (!formName.trim()) {
      toast.error("Engineer name is required")
      return
    }
    if (!formEmail.trim()) {
      toast.error("Email is required")
      return
    }
    if (!formBranchId) {
      toast.error("Please select a branch")
      return
    }

    const branch = myBranches.find((b) => b.id === formBranchId)
    const team = myTeams.find((t) => t.id === formTeamId)

    if (editingEngineer) {
      updateEngineer(editingEngineer.id, {
        name: formName,
        email: formEmail,
        phone: formPhone,
        branchId: formBranchId,
        branchName: branch?.name ?? "",
        teamId: formTeamId || undefined,
        teamName: team?.name || undefined,
        role: formRole,
        status: formStatus,
      })
      toast.success("Engineer updated successfully")
    } else {
      addEngineer({
        name: formName,
        email: formEmail,
        phone: formPhone,
        branchId: formBranchId,
        branchName: branch?.name ?? "",
        dmaId,
        teamId: formTeamId || undefined,
        teamName: team?.name || undefined,
        role: formRole,
        status: formStatus,
      })
      toast.success("Engineer added successfully")
    }

    setDialogOpen(false)
  }

  function handleDelete() {
    if (deleteId) {
      deleteEngineer(deleteId)
      toast.success("Engineer removed successfully")
      setDeleteId(null)
    }
  }

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        title="Engineer Management"
        description="Manage engineers and assign them to branches and teams"
        actionLabel="Add Engineer"
        actionIcon={Users}
        onAction={openCreateDialog}
      />

      {/* Filters */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <div className="relative max-w-sm flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search engineers..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-40">
            <SelectValue placeholder="Status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="active">Active</SelectItem>
            <SelectItem value="inactive">Inactive</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b text-left text-muted-foreground">
                  <th className="px-6 py-3 font-medium">Name</th>
                  <th className="px-6 py-3 font-medium">Email</th>
                  <th className="px-6 py-3 font-medium">Branch</th>
                  <th className="px-6 py-3 font-medium">Team</th>
                  <th className="px-6 py-3 font-medium">Role</th>
                  <th className="px-6 py-3 font-medium text-center">
                    Reports
                  </th>
                  <th className="px-6 py-3 font-medium">Status</th>
                  <th className="px-6 py-3 font-medium text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredEngineers.length === 0 ? (
                  <tr>
                    <td
                      colSpan={8}
                      className="px-6 py-12 text-center text-muted-foreground"
                    >
                      No engineers found
                    </td>
                  </tr>
                ) : (
                  filteredEngineers.map((engineer) => (
                    <tr key={engineer.id} className="hover:bg-muted/50">
                      <td className="px-6 py-4 font-medium">
                        {engineer.name}
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        {engineer.email}
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        <div className="flex items-center gap-1.5">
                          <GitBranch className="h-3.5 w-3.5" />
                          {engineer.branchName}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        {engineer.teamName ?? "-"}
                      </td>
                      <td className="px-6 py-4">
                        <Badge
                          variant={
                            engineer.role === "team_leader"
                              ? "default"
                              : "secondary"
                          }
                          className="text-[11px]"
                        >
                          {engineer.role === "team_leader"
                            ? "Team Leader"
                            : "Engineer"}
                        </Badge>
                      </td>
                      <td className="px-6 py-4 text-center">
                        {engineer.assignedReports}
                      </td>
                      <td className="px-6 py-4">
                        <EntityStatusBadge status={engineer.status} />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8"
                            >
                              <MoreHorizontal className="h-4 w-4" />
                              <span className="sr-only">Actions</span>
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuItem
                              onClick={() => {
                                setViewingEngineer(engineer)
                                setDetailOpen(true)
                              }}
                            >
                              <Eye className="mr-2 h-4 w-4" />
                              View
                            </DropdownMenuItem>
                            <DropdownMenuItem
                              onClick={() => openEditDialog(engineer)}
                            >
                              <Pencil className="mr-2 h-4 w-4" />
                              Edit
                            </DropdownMenuItem>
                            <DropdownMenuItem
                              onClick={() => setDeleteId(engineer.id)}
                              className="text-red-600 focus:text-red-600"
                            >
                              <Trash2 className="mr-2 h-4 w-4" />
                              Remove
                            </DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {/* Detail Modal */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Engineer Profile</DialogTitle>
          </DialogHeader>
          {viewingEngineer && (
            <div className="flex flex-col gap-4 py-4">
              <div className="flex items-center gap-4">
                <div className="flex h-14 w-14 items-center justify-center rounded-full bg-primary/10 text-primary">
                  <Users className="h-7 w-7" />
                </div>
                <div>
                  <h3 className="text-lg font-semibold">
                    {viewingEngineer.name}
                  </h3>
                  <Badge
                    variant={
                      viewingEngineer.role === "team_leader"
                        ? "default"
                        : "secondary"
                    }
                  >
                    {viewingEngineer.role === "team_leader"
                      ? "Team Leader"
                      : "Engineer"}
                  </Badge>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3 rounded-lg bg-muted/50 p-4 text-sm">
                <div className="flex items-center gap-2 text-muted-foreground">
                  <Mail className="h-4 w-4" />
                  {viewingEngineer.email}
                </div>
                <div className="flex items-center gap-2 text-muted-foreground">
                  <Phone className="h-4 w-4" />
                  {viewingEngineer.phone}
                </div>
                <div className="flex items-center gap-2 text-muted-foreground">
                  <GitBranch className="h-4 w-4" />
                  {viewingEngineer.branchName}
                </div>
                <div className="flex items-center gap-2 text-muted-foreground">
                  <UserCog className="h-4 w-4" />
                  {viewingEngineer.teamName ?? "No team"}
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="text-sm">
                  <span className="text-muted-foreground">Status: </span>
                  <EntityStatusBadge status={viewingEngineer.status} />
                </div>
                <div className="text-sm">
                  <span className="text-muted-foreground">
                    Assigned Reports:{" "}
                  </span>
                  <span className="font-semibold">
                    {viewingEngineer.assignedReports}
                  </span>
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingEngineer ? "Edit Engineer" : "Add Engineer"}
            </DialogTitle>
          </DialogHeader>
          <div className="flex flex-col gap-4 py-4">
            <div className="flex flex-col gap-2">
              <Label htmlFor="eng-name">Full Name</Label>
              <Input
                id="eng-name"
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g., John Smith"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label htmlFor="eng-email">Email</Label>
                <Input
                  id="eng-email"
                  type="email"
                  value={formEmail}
                  onChange={(e) => setFormEmail(e.target.value)}
                  placeholder="email@hydranet.gov"
                />
              </div>
              <div className="flex flex-col gap-2">
                <Label htmlFor="eng-phone">Phone</Label>
                <Input
                  id="eng-phone"
                  value={formPhone}
                  onChange={(e) => setFormPhone(e.target.value)}
                  placeholder="+27 XX XXX XXXX"
                />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label>Branch</Label>
                <Select value={formBranchId} onValueChange={setFormBranchId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select branch" />
                  </SelectTrigger>
                  <SelectContent>
                    {myBranches.map((b) => (
                      <SelectItem key={b.id} value={b.id}>
                        {b.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="flex flex-col gap-2">
                <Label>Team (Optional)</Label>
                <Select value={formTeamId} onValueChange={setFormTeamId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select team" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">No Team</SelectItem>
                    {myTeams.map((t) => (
                      <SelectItem key={t.id} value={t.id}>
                        {t.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="flex flex-col gap-2">
                <Label>Role</Label>
                <Select
                  value={formRole}
                  onValueChange={(v) =>
                    setFormRole(v as "engineer" | "team_leader")
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="engineer">Engineer</SelectItem>
                    <SelectItem value="team_leader">Team Leader</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="flex flex-col gap-2">
                <Label>Status</Label>
                <Select
                  value={formStatus}
                  onValueChange={(v) => setFormStatus(v as EntityStatus)}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="active">Active</SelectItem>
                    <SelectItem value="inactive">Inactive</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit}>
              {editingEngineer ? "Save Changes" : "Add Engineer"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteId}
        onOpenChange={() => setDeleteId(null)}
        title="Remove Engineer"
        description="Are you sure you want to remove this engineer? This action cannot be undone."
        confirmLabel="Remove Engineer"
        onConfirm={handleDelete}
      />
    </div>
  )
}
